import { _ as _export_sfc, o as openBlock, c as createElementBlock, ag as createStaticVNode } from "./chunks/framework.DNT4b13o.js";
const __pageData = JSON.parse('{"title":"FlashQL","description":"","frontmatter":{},"headers":[],"relativePath":"flashql.md","filePath":"flashql.md"}');
const _sfc_main = { name: "flashql.md" };
function _sfc_render(_ctx, _cache, $props, $setup, $data, $options) {
  return openBlock(), createElementBlock("div", null, [..._cache[0] || (_cache[0] = [
    createStaticVNode('<h1 id="flashql" tabindex="-1">FlashQL <a class="header-anchor" href="#flashql" aria-label="Permalink to &quot;FlashQL&quot;">​</a></h1><p><em>A full SQL runtime for the local process, the browser, the edge, and the offline world.</em></p><p>FlashQL is LinkedQL&#39;s embeddable database engine: a complete in-process SQL runtime that runs anywhere JavaScript does, including Node.js, the browser, workers, and edge runtimes.</p><p>FlashQL brings together:</p><ul><li>a full relational SQL engine</li><li>live queries</li><li>federation, materialization, and sync</li><li>observable commit stream via a Write-Ahead Log (WAL)</li><li>transactional local storage, with MVCC-based architecture</li><li>point-in-time boot through version-aware replay</li></ul><h2 id="why-flashql" tabindex="-1">Why FlashQL <a class="header-anchor" href="#why-flashql" aria-label="Permalink to &quot;Why FlashQL&quot;">​</a></h2><p>Modern applications increasingly need database power in places where a traditional database server is inconvenient, expensive, unavailable, or simply the wrong abstraction.</p><p>Sometimes you want:</p><ul><li>a real query engine inside the app itself</li><li>a local store that survives network loss</li><li>one relational graph that spans local and remote data</li><li>reactivity over query results, not just table events</li><li>the ability to materialize or keep remote relations hot locally</li></ul><p>Just spin up a FlashQL instance and run SQL:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 2::text AS value</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">// [{ value: &#39;2&#39; }]</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is the smallest useful FlashQL shape:</p><ul><li>create the client</li><li>connect it</li><li>run SQL</li><li>disconnect it</li></ul><p>The goal is application-level SQL power in places where an embeddable runtime is the right tool.</p><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>FlashQL is ephemeral by default, but it becomes a persistent local runtime when you attach a <code>keyval</code> backend.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> IndexedDBKV</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@webqit/keyval/indexeddb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#F07178;">  keyval</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> IndexedDBKV</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> path</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">my-app</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With a <code>keyval</code> backend:</p><ul><li>schema and data survive reloads</li><li>WAL history is persisted</li><li>sync state is persisted</li><li>FlashQL becomes appropriate for browser PWAs and local-first applications</li></ul><p>Without a persistence backend, the engine is still useful for tests, ephemeral sessions, and in-process computation, but the state disappears when the process ends.</p><h2 id="dialects" tabindex="-1">Dialects <a class="header-anchor" href="#dialects" aria-label="Permalink to &quot;Dialects&quot;">​</a></h2><p>FlashQL supports both PostgreSQL-flavored and MySQL-flavored SQL.</p><p>Set a default dialect at the client level:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Optionally override it per query:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT `name` FROM `users`</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mysql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Where not specified, FlashQL defaults to <code>postgres</code>.</p><h2 id="compatibility-in-practice" tabindex="-1">Compatibility in Practice <a class="header-anchor" href="#compatibility-in-practice" aria-label="Permalink to &quot;Compatibility in Practice&quot;">​</a></h2><p>FlashQL speaks real SQL, but it is not trying to be a byte-for-byte clone of PostgreSQL or MySQL.</p><p>The goal is to cover the application-facing surface of SQL that actually matters in code:</p><ul><li>queries</li><li>mutations</li><li>schema operations</li><li>expressions</li><li>relational composition</li></ul><p>It also adds LinkedQL-specific capabilities such as DeepRefs, version binding, and structured JSON-style language features.</p><p>See the <a href="/flashql/lang">FlashQL Language Reference</a> for the current documented surface.</p><p>Two advanced PostgreSQL-flavored examples give a sense of scope:</p><hr><details><summary>Query 1: writable CTEs, LATERAL joins, aggregates, and windows</summary><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> rows </span><span style="color:#89DDFF;">}</span><span style="color:#89DDFF;"> =</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>\n<span class="line"><span style="color:#89DDFF;">  `</span><span style="color:#C3E88D;">WITH</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">      updated AS (</span></span>\n<span class="line"><span style="color:#C3E88D;">        UPDATE users</span></span>\n<span class="line"><span style="color:#C3E88D;">        SET status = &#39;inactive&#39;</span></span>\n<span class="line"><span style="color:#C3E88D;">        WHERE last_login &lt; NOW() - INTERVAL &#39;90 days&#39;</span></span>\n<span class="line"><span style="color:#C3E88D;">        RETURNING id, name, department, last_login</span></span>\n<span class="line"><span style="color:#C3E88D;">      ),</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">      metrics AS (</span></span>\n<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">          u.id,</span></span>\n<span class="line"><span style="color:#C3E88D;">          u.name,</span></span>\n<span class="line"><span style="color:#C3E88D;">          u.department,</span></span>\n<span class="line"><span style="color:#C3E88D;">          m.avg_total,</span></span>\n<span class="line"><span style="color:#C3E88D;">          m.order_rank</span></span>\n<span class="line"><span style="color:#C3E88D;">        FROM updated u</span></span>\n<span class="line"><span style="color:#C3E88D;">        LEFT JOIN LATERAL (</span></span>\n<span class="line"><span style="color:#C3E88D;">          SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">            AVG(total) AS avg_total,</span></span>\n<span class="line"><span style="color:#C3E88D;">            RANK() OVER (ORDER BY SUM(total) DESC) AS order_rank</span></span>\n<span class="line"><span style="color:#C3E88D;">          FROM orders o</span></span>\n<span class="line"><span style="color:#C3E88D;">          WHERE o.user_id = u.id</span></span>\n<span class="line"><span style="color:#C3E88D;">          GROUP BY o.user_id</span></span>\n<span class="line"><span style="color:#C3E88D;">        ) m ON TRUE</span></span>\n<span class="line"><span style="color:#C3E88D;">      ),</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">      aggregates AS (</span></span>\n<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">          department,</span></span>\n<span class="line"><span style="color:#C3E88D;">          COUNT(*) AS user_count,</span></span>\n<span class="line"><span style="color:#C3E88D;">          ROUND(AVG(avg_total), 2) AS avg_order_total,</span></span>\n<span class="line"><span style="color:#C3E88D;">          GROUPING(department) AS dept_grouped</span></span>\n<span class="line"><span style="color:#C3E88D;">        FROM metrics</span></span>\n<span class="line"><span style="color:#C3E88D;">        GROUP BY CUBE (department)</span></span>\n<span class="line"><span style="color:#C3E88D;">      )</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">      a.department,</span></span>\n<span class="line"><span style="color:#C3E88D;">      a.user_count,</span></span>\n<span class="line"><span style="color:#C3E88D;">      a.avg_order_total,</span></span>\n<span class="line"><span style="color:#C3E88D;">      SUM(a.user_count) OVER () AS total_users,</span></span>\n<span class="line"><span style="color:#C3E88D;">      RANK() OVER (ORDER BY a.avg_order_total DESC NULLS LAST) AS perf_rank</span></span>\n<span class="line"><span style="color:#C3E88D;">    FROM aggregates a</span></span>\n<span class="line"><span style="color:#C3E88D;">    ORDER BY a.department NULLS LAST</span><span style="color:#89DDFF;">`</span></span>\n<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(rows)</span><span style="color:#89DDFF;">;</span></span></code></pre></div></details><p>Capabilities demonstrated:</p><ul><li><code>WITH</code> and writable CTEs</li><li><code>UPDATE ... RETURNING</code></li><li><code>JOIN LATERAL</code></li><li>aggregate and window functions</li><li>analytic grouping such as <code>CUBE</code> and <code>GROUPING()</code></li></ul><p>Cause and effect in this query:</p><ul><li>a writable CTE mutates and returns rows</li><li>a lateral join derives per-row metrics from that result</li><li>the final query computes aggregate and ranking outputs from the transformed relation</li></ul><hr><details><summary>Query 2: VALUES, ROWS FROM, grouping sets, and set operations</summary><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> rows </span><span style="color:#89DDFF;">}</span><span style="color:#89DDFF;"> =</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>\n<span class="line"><span style="color:#89DDFF;">  `</span><span style="color:#C3E88D;">WITH</span></span>\n<span class="line"><span style="color:#C3E88D;">      recent_logins AS (</span></span>\n<span class="line"><span style="color:#C3E88D;">        SELECT *</span></span>\n<span class="line"><span style="color:#C3E88D;">        FROM (VALUES</span></span>\n<span class="line"><span style="color:#C3E88D;">          (1, &#39;2025-10-01&#39;::date),</span></span>\n<span class="line"><span style="color:#C3E88D;">          (2, &#39;2025-10-15&#39;::date),</span></span>\n<span class="line"><span style="color:#C3E88D;">          (3, &#39;2025-10-20&#39;::date)</span></span>\n<span class="line"><span style="color:#C3E88D;">        ) AS t(user_id, last_login)</span></span>\n<span class="line"><span style="color:#C3E88D;">      ),</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">      generated AS (</span></span>\n<span class="line"><span style="color:#C3E88D;">        SELECT *</span></span>\n<span class="line"><span style="color:#C3E88D;">        FROM ROWS FROM (</span></span>\n<span class="line"><span style="color:#C3E88D;">          generate_series(1, 3) AS gen_id,</span></span>\n<span class="line"><span style="color:#C3E88D;">          unnest(ARRAY[&#39;A&#39;, &#39;B&#39;, &#39;C&#39;]) AS label</span></span>\n<span class="line"><span style="color:#C3E88D;">        )</span></span>\n<span class="line"><span style="color:#C3E88D;">      ),</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">      enriched AS (</span></span>\n<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">          u.id,</span></span>\n<span class="line"><span style="color:#C3E88D;">          u.name,</span></span>\n<span class="line"><span style="color:#C3E88D;">          r.last_login,</span></span>\n<span class="line"><span style="color:#C3E88D;">          g.label,</span></span>\n<span class="line"><span style="color:#C3E88D;">          COALESCE(o.total, 0) AS total_spent</span></span>\n<span class="line"><span style="color:#C3E88D;">        FROM users u</span></span>\n<span class="line"><span style="color:#C3E88D;">        JOIN recent_logins r ON r.user_id = u.id</span></span>\n<span class="line"><span style="color:#C3E88D;">        JOIN generated g ON g.gen_id = u.id</span></span>\n<span class="line"><span style="color:#C3E88D;">        LEFT JOIN (VALUES</span></span>\n<span class="line"><span style="color:#C3E88D;">          (1, 1200),</span></span>\n<span class="line"><span style="color:#C3E88D;">          (2, 500),</span></span>\n<span class="line"><span style="color:#C3E88D;">          (3, 900)</span></span>\n<span class="line"><span style="color:#C3E88D;">        ) AS o(user_id, total) ON o.user_id = u.id</span></span>\n<span class="line"><span style="color:#C3E88D;">      ),</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">      grouped AS (</span></span>\n<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">          label,</span></span>\n<span class="line"><span style="color:#C3E88D;">          DATE_TRUNC(&#39;month&#39;, last_login) AS login_month,</span></span>\n<span class="line"><span style="color:#C3E88D;">          COUNT(*) AS active_users,</span></span>\n<span class="line"><span style="color:#C3E88D;">          SUM(total_spent) AS revenue</span></span>\n<span class="line"><span style="color:#C3E88D;">        FROM enriched</span></span>\n<span class="line"><span style="color:#C3E88D;">        GROUP BY GROUPING SETS (</span></span>\n<span class="line"><span style="color:#C3E88D;">          (label, login_month),</span></span>\n<span class="line"><span style="color:#C3E88D;">          (label),</span></span>\n<span class="line"><span style="color:#C3E88D;">          ()</span></span>\n<span class="line"><span style="color:#C3E88D;">        )</span></span>\n<span class="line"><span style="color:#C3E88D;">      )</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#C3E88D;">    SELECT * FROM grouped</span></span>\n<span class="line"><span style="color:#C3E88D;">    UNION ALL</span></span>\n<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">      label,</span></span>\n<span class="line"><span style="color:#C3E88D;">      NULL AS login_month,</span></span>\n<span class="line"><span style="color:#C3E88D;">      0 AS active_users,</span></span>\n<span class="line"><span style="color:#C3E88D;">      0 AS revenue</span></span>\n<span class="line"><span style="color:#C3E88D;">    FROM generated</span></span>\n<span class="line"><span style="color:#C3E88D;">    EXCEPT</span></span>\n<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">      label,</span></span>\n<span class="line"><span style="color:#C3E88D;">      NULL,</span></span>\n<span class="line"><span style="color:#C3E88D;">      0,</span></span>\n<span class="line"><span style="color:#C3E88D;">      0</span></span>\n<span class="line"><span style="color:#C3E88D;">    FROM grouped</span></span>\n<span class="line"><span style="color:#C3E88D;">    INTERSECT</span></span>\n<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>\n<span class="line"><span style="color:#C3E88D;">      label,</span></span>\n<span class="line"><span style="color:#C3E88D;">      NULL,</span></span>\n<span class="line"><span style="color:#C3E88D;">      0,</span></span>\n<span class="line"><span style="color:#C3E88D;">      0</span></span>\n<span class="line"><span style="color:#C3E88D;">    FROM grouped</span></span>\n<span class="line"><span style="color:#C3E88D;">    ORDER BY label NULLS LAST</span><span style="color:#89DDFF;">`</span></span>\n<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(rows)</span><span style="color:#89DDFF;">;</span></span></code></pre></div></details><p>Capabilities demonstrated:</p><ul><li>inline <code>VALUES</code> tables</li><li><code>ROWS FROM</code> and set-returning functions</li><li>grouping sets</li><li>combined set operations</li><li>ordering with <code>NULLS LAST</code></li></ul><p>These examples show the shape of SQL FlashQL can execute.</p><h2 id="the-common-query-surface" tabindex="-1">The Common Query Surface <a class="header-anchor" href="#the-common-query-surface" aria-label="Permalink to &quot;The Common Query Surface&quot;">​</a></h2><p>FlashQL supports the same top-level application contract as the other LinkedQL clients:</p><ul><li><code>db.query()</code></li><li><code>db.query({ live: true })</code></li><li><code>db.stream()</code></li><li><code>db.transaction()</code></li><li><code>db.wal.subscribe()</code></li></ul><p>And then extends that with:</p><ul><li><code>db.sync.sync()</code></li></ul><h2 id="live-queries-streams-and-the-commit-stream-wal" tabindex="-1">Live Queries, Streams, and the Commit Stream (WAL) <a class="header-anchor" href="#live-queries-streams-and-the-commit-stream-wal" aria-label="Permalink to &quot;Live Queries, Streams, and the Commit Stream (WAL)&quot;">​</a></h2><p>FlashQL supports modern application data flows directly.</p><h3 id="live-queries" tabindex="-1">Live Queries <a class="header-anchor" href="#live-queries" aria-label="Permalink to &quot;Live Queries&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>\n<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, name FROM public.users ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>\n<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">// current rows; the array keeps tracking the query as local state changes</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Use live queries when the application wants the query result itself to remain current over time.</p><p>Take a deep dive in:</p><ul><li><a href="/realtime/live-queries">Live Queries</a></li></ul><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.big_table ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)) </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>This lets you consume large results lazily instead of buffering the full result in memory first.</p><p>See more in <a href="/api/stream">db.stream()</a></p><h3 id="the-commit-stream-wal" tabindex="-1">The Commit Stream (WAL) <a class="header-anchor" href="#the-commit-stream-wal" aria-label="Permalink to &quot;The Commit Stream (WAL)&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>\n<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>\n<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(commit)</span></span>\n<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#82AAFF;"> unsubscribe</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This observes table commits directly instead of maintaining a query-shaped live view.</p><p>Use WAL subscriptions when you care about table-level commit events directly.</p><p>See: <a href="/realtime/changefeeds">Changefeeds</a></p><h2 id="transactions-and-the-multi-version-concurrency-control-mvcc-architecture" tabindex="-1">Transactions and the Multi-Version Concurrency Control (MVCC) Architecture <a class="header-anchor" href="#transactions-and-the-multi-version-concurrency-control-mvcc-architecture" aria-label="Permalink to &quot;Transactions and the Multi-Version Concurrency Control (MVCC) Architecture&quot;">​</a></h2><p>FlashQL uses <strong>Multi-Version Concurrency Control (MVCC)</strong>, the same core model used by PostgreSQL.</p><p>Every write creates a new version of a row, and every transaction reads from a <strong>consistent snapshot in time</strong>.</p><p>While you don&#39;t think about it, each query you run</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>\n<span class="line"><span style="color:#89DDFF;">  `</span><span style="color:#C3E88D;">INSERT INTO public.users (id, name)</span></span>\n<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada&#39;);</span></span>\n<span class="line"><span style="color:#C3E88D;">  DELETE FROM public.orders WHERE id = 2;</span><span style="color:#89DDFF;">`</span></span>\n<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>executes within a transaction. Errors are isolated to that transaction, and the entire operation is automatically rolled back on error.</p><p>Internally:</p><ul><li>transactions don’t overwrite rows—they produce new versions</li><li>each transaction sees a stable view of the database</li><li>reads and writes don’t block each other</li></ul><p>If you’ve used PostgreSQL, this is the same idea—just running locally, in-process.</p><p>Because everything is versioned, FlashQL can layer on:</p><ul><li><strong>a row-version-aware sync engine</strong></li><li><strong>WAL-based change streams</strong></li><li><strong>replay and point-in-time boot</strong></li></ul><p>—all without introducing a separate model for reactivity or sync.</p><h2 id="federation-materialization-and-sync" tabindex="-1">Federation, Materialization, and Sync <a class="header-anchor" href="#federation-materialization-and-sync" aria-label="Permalink to &quot;Federation, Materialization, and Sync&quot;">​</a></h2><p>FlashQL can compute both local and remote data in <strong>the same query</strong>.</p><p>You simply define a table locally (a database view precisely) to mirror remote data; you decide how it behaves locally in one of three modes:</p><ul><li><strong>federated</strong> — querying the table queries the source directly</li><li><strong>materialized</strong> — the table is a materialized copy of the source data</li><li><strong>realtime</strong> — the table materializes and stays in sync with source data</li></ul><p>Your code sees normal tables:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#89DDFF;"> *</span></span>\n<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.local_users u</span></span>\n<span class="line"><span style="color:#F78C6C;">JOIN</span><span style="color:#BABED8;"> public.remote_orders o </span><span style="color:#F78C6C;">ON</span><span style="color:#BABED8;"> o.user_id </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> u.id;</span></span></code></pre></div><p>FlashQL computes the local + remote data as one relational graph.</p><p>What changes is what you don&#39;t get to build:</p><ul><li>dedicated REST APIs for reads</li><li>caching layers for performance</li><li>subscription systems (e.g. GraphQL) for updates</li><li>a dedicated sync engine to synchronize local and remote states</li><li>the orchestration layer for the whole system</li></ul><p>FlashQL is designed as a drop-in primitive for the modern app.</p><p>Take a deep dive in:</p><ul><li><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></li><li><a href="/flashql/sync-api">The Sync API</a></li></ul><h2 id="point-in-time-boot" tabindex="-1">Point-in-Time Boot <a class="header-anchor" href="#point-in-time-boot" aria-label="Permalink to &quot;Point-in-Time Boot&quot;">​</a></h2><p>FlashQL can boot itself to a point in history – the state of the database at a certain table name and version.</p><h3 id="read-only-historical-boot" tabindex="-1">Read-Only Historical Boot <a class="header-anchor" href="#read-only-historical-boot" aria-label="Permalink to &quot;Read-Only Historical Boot&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> historical </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> historical</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>versionStop</code>, FlashQL replays itself to the time when the database had the specified table at the specified version.</p><p>The effect is that the runtime boots against that historical boundary instead of replaying all the way forward to the latest state.</p><p>By default, that boot is read-only. Rewriting the hostory from that point forward is possible with an explicit opt-in:</p><h4 id="overwriteforward-true" tabindex="-1"><code>overwriteForward: true</code> <a class="header-anchor" href="#overwriteforward-true" aria-label="Permalink to &quot;`overwriteForward: true`&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> branch </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#F07178;">  overwriteForward</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> branch</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>overwriteForward: true</code>, FlashQL keeps the history intact until the first mutating commit is made, then truncates forward histories and lets you continue from that historical point.</p><p>That turns the historical boot into a branch point: read-only until the first write, then writable from that point forward.</p><p>See also:</p><ul><li><a href="/lang/version-binding">Version Binding</a></li></ul><h2 id="where-to-go-next" tabindex="-1">Where to Go Next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to Go Next&quot;">​</a></h2><ul><li><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></li><li><a href="/flashql/sync-api">The Sync API</a></li><li><a href="/api/">API</a></li><li><a href="/flashql/lang">FlashQL Language Reference</a></li></ul>', 105)
  ])]);
}
const flashql = /* @__PURE__ */ _export_sfc(_sfc_main, [["render", _sfc_render]]);
export {
  __pageData,
  flashql as default
};
